mapper.update:
UPDATE TB_CERTIFICATE_APPLY
SET DEL_YN = 'Y'
WHERE CERT_SEQ = #{certSeq}

mapper.select:
SELECT * FROM TB_CERTIFICATE_APPLY
WHERE APPLY_NM = #{applyNm}
  AND PHONE = #{phone}
  AND DEL_YN = 'N'
ORDER BY REG_DT DESC

SELECT COUNT(CERT_SEQ)
FROM TB_CERTIFICATE_APPLY
WHERE CERT_TYPE = #{certType}
  AND APPLY_NM = #{applyNm}
  AND PHONE = #{phone}
  AND DEL_YN = 'N'
  AND ISSUE_STATUS IN ('WAIT', 'ING', 'DONE')

SELECT * FROM TB_CERTIFICATE_APPLY
WHERE APPLY_NM = #{applyNm}
  AND PHONE = #{phone}
  AND EMAIL = #{email}
  AND CERT_TYPE = #{certType}
  AND DEL_YN = 'N'
ORDER BY REG_DT DESC
LIMIT 1
